#include <stdio.h>
#include <pthread.h>

typedef struct {
    int task_id;
    int result;
} Task;

void *worker(void *arg) {
    Task *t = (Task *)arg;
    t->result = t->task_id * t->task_id;
    printf("Worker task %d: result = %d\n", t->task_id, t->result);
    return NULL;
}

int main(void) {
    pthread_t threads[3];
    Task tasks[3];
    for (int i = 0; i < 3; i++) {
        tasks[i].task_id = i + 1;
        tasks[i].result = 0;
        pthread_create(&threads[i], NULL, worker, &tasks[i]);
        pthread_join(threads[i], NULL);
    }
    printf("All tasks done.\n");
    return 0;
}

