#include <pthread.h>

/* == EXEMPLE ===============================================
 * Pool simple : 2 workers calculent des factorielles
 * ========================================================= */
typedef struct { int n; int fact; } ExTask;
void *ex_worker(void *arg) {
    ExTask *t = (ExTask *)arg;
    t->fact = 1;
    for (int i = 2; i <= t->n; i++) t->fact *= i;
    printf("Fact(%d) = %d\n", t->n, t->fact);
    return NULL;
}
